        int diag1_right = 0;
        int diag2_left = 0;
        int diag2_right = 0;

        int i = 0;
        int j = n - 1;

        while (i < n) {
            if (i < n / 2) {
                diag1_left += mat[i][i];
                diag2_left += mat[j][i];
