public class SpiralMatrix {
    public static void spiralFill(int m, int n, int[][] a) {
        int val = 1;
        int k = 0, l = 0;

        while (k < m && l < n) {
            // Fill the first row from the remaining rows
            for (int i = l; i < n; i++) {
                a[k][i] = val;
                val++;
            }
            k++;

            // Fill the last column from the remaining columns
            for (int i = k; i < m; i++) {
                a[i][n - 1] = val;
                val++;
            }
            n--;

            // Fill the last row from the remaining rows
            if (k < m) {
                for (int i = n - 1; i >= l; i--) {
                    a[m - 1][i] = val;
                    val++;
                }
                m--;
            }

            // Fill the first column from the remaining columns
            if (l < n) {
                for (int i = m - 1; i >= k; i--) {
                    a[i][l] = val;
                    val++;
                }
                l++;
            }
