public class PalindromeCounter {
    public static int CountPS(String str, int n) {
        int[][] dp = new int[n][n];
        boolean[][] P = new boolean[n][n];

        // Initialize single character palindromes
        for (int i = 0; i < n; i++) {
            P[i][i] = true;
        }

        // Initialize 2-character palindromes
        for (int i = 0; i < n - 1; i++) {
            if (str.charAt(i) == str.charAt(i + 1)) {
                P[i][i + 1] = true;
                dp[i][i + 1] = 1;
            }
        }

        // Fill the dp and P tables for substrings of length 3 to n
        for (int gap = 2; gap < n; gap++) {
            for (int i = 0; i < n - gap; i++) {
                int j = gap + i;

                // Check if substring from i to j is palindrome
                if (str.charAt(i) == str.charAt(j) && P[i + 1][j - 1]) {
                    P[i][j] = true;
                }

                // Calculate count of palindromic substrings
                if (P[i][j]) {
                    dp[i][j] = dp[i][j - 1] + dp[i + 1][j] + 1 - dp[i + 1][j - 1];
                } else {
                    dp[i][j] = dp[i][j - 1] + dp[i + 1][j] - dp[i + 1][j - 1];
                }
            }
        }

        return dp[0][n - 1];
    }

    public static void main(String[] args) {
        String str = "aab";
        int n = str.length();
        System.out.println("Total palindromic subsequences: " + CountPS(str, n));
    }
}
