        int i = 0;
        for (int j = gap; j < n; j++) {
            T[i][j] = F[i][j] = 0;
            for (int g = 0; g < gap; g++) {
                int k = i + g;
                int tik = T[i][k] + F[i][k];
                int tkj = T[k + 1][j] + F[k + 1][j];

