import java.util.*;

public class KthLargestSubarraySum {

    public static int kthLargestSum(int[] arr, int n, int k) {
        // Create prefix sum array
        int[] sum = new int[n + 1];
        sum[0] = 0;
        sum[1] = arr[0];

        for (int i = 2; i <= n; i++) {
            sum[i] = sum[i - 1] + arr[i - 1];
        }

        // Min heap to track k largest sums
        PriorityQueue<Integer> minHeap = new PriorityQueue<>();

        // Generate all possible subarrays and maintain k largest sums
        for (int i = 1; i <= n; i++) {
            for (int j = i; j <= n; j++) {
                int x = sum[j] - sum[i - 1];

                if (minHeap.size() < k) {
                    minHeap.offer(x);
                } else {
                    if (minHeap.peek() < x) {
                        minHeap.poll();
                        minHeap.offer(x);
                    }
                }
            }
        }

        // Return the kth largest sum (top of min heap)
        return minHeap.peek();
    }

    public static void main(String[] args) {
        // Example usage
        int[] arr = {1, 2, 3, 4};
        int n = arr.length;
        int k = 3;
        System.out.println("Kth largest subarray sum: " + kthLargestSum(arr, n, k));
    }
}
