public static boolean prevPermutation(char[] str) {
    int n = str.length - 1;
    int i = n;

    // Find the largest index i such that str[i-1] > str[i]
    while (i > 0 && str[i - 1] <= str[i]) {
        i--;
    }

    // If no such index exists, this is the lexicographically smallest permutation
    if (i <= 0) {
        return false;
    }

    // Find the largest index j such that str[j] < str[i-1]
    int j = i - 1;
    while (j + 1 <= n && str[j + 1] < str[i - 1]) {
        j++;
    }

    // Swap str[i-1] and str[j]
    char temp = str[i - 1];
    str[i - 1] = str[j];
    str[j] = temp;

    // Reverse the suffix starting at position i
    reverse(str, i, n);

    return true;
}

