    public double largestSumOfAverages(int[] A, int K) {
        int n = A.length;
        double[] preSum = new double[n + 1];
        preSum[0] = 0;

        for (int i = 0; i < n; i++) {
            preSum[i + 1] = preSum[i] + A[i];
