import java.util.HashMap;
import java.util.Map;

public class Solution {
    public static int maxNumOfChocolates(int[] arr, int n, int k) {
        Map<Integer, Integer> um = new HashMap<>();
        int currRem = 0, maxSum = 0;
        int[] sm = new int[n];

        // Build prefix sum array
        sm[0] = arr[0];
        for (int i = 1; i < n; i++) {
            sm[i] = sm[i - 1] + arr[i];
        }

        // Find maximum sum divisible by k
        for (int i = 0; i < n; i++) {
            currRem = sm[i] % k;

            if (currRem == 0 && maxSum < sm[i]) {
                maxSum = sm[i];
            } else if (!um.containsKey(currRem)) {
                um.put(currRem, i);
            } else if (maxSum < (sm[i] - sm[um.get(currRem)])) {
                maxSum = sm[i] - sm[um.get(currRem)];
            }
        }

        return maxSum / k;
    }
}
