public static int solve(String X, String Y, int l, int r, int k, int[][][] dp) {
    if (k == 0) {
        return 0;
    }
    if (l < 0 || r < 0) {
        return 1000000000;
    }
    if (dp[l][r][k] != -1) {
        return dp[l][r][k];
    }

    int cost = (X.charAt(l) - 'a') ^ (Y.charAt(r) - 'a');

    int option1 = cost + solve(X, Y, l - 1, r - 1, k - 1, dp);
    int option2 = solve(X, Y, l - 1, r, k, dp);
    int option3 = solve(X, Y, l, r - 1, k, dp);

    dp[l][r][k] = Math.min(option1, Math.min(option2, option3));

    return dp[l][r][k];
}
