public static int MinimumCost(int[] cost, int n, int W) {
    final int INF = Integer.MAX_VALUE;

    List<Integer> val = new ArrayList<>();
    List<Integer> wt = new ArrayList<>();
    int size = 0;

    for (int i = 0; i < n; i++) {
        if (cost[i] != -1) {
            val.add(cost[i]);
            wt.add(i + 1);
            size++;
        }
    }

    n = size;
    int[][] min_cost = new int[n + 1][W + 1];

    for (int i = 0; i <= W; i++) {
        min_cost[0][i] = INF;
    }

    for (int i = 1; i <= n; i++) {
        min_cost[i][0] = 0;
    }

    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= W; j++) {
            if (wt.get(i - 1) > j) {
                min_cost[i][j] = min_cost[i - 1][j];
            } else {
                min_cost[i][j] = Math.min(min_cost[i - 1][j], 
                                         min_cost[i][j - wt.get(i - 1)] + val.get(i - 1));
            }
        }
    }

    if (min_cost[n][W] == INF) {
        return -1;
    } else {
        return min_cost[n][W];
    }
