public static int getMinSteps(int n) {
    int[] table = new int[n + 1];

    // Initialize table with base case (subtract 1 repeatedly)
    for (int i = 0; i <= n; i++) {
        table[i] = n - i;
    }

    // Work backwards to find optimal solutions
    for (int i = n; i >= 1; i--) {
        if (i % 2 == 0) {
            table[i / 2] = Math.min(table[i] + 1, table[i / 2]);
        }
        if (i % 3 == 0) {
