public static void segregateElements(int[] arr, int n) {
    int[] temp = new int[n];
    int j = 0;

    // First pass: copy all non-negative elements
    for (int i = 0; i < n; i++) {
        if (arr[i] >= 0) {
            temp[j] = arr[i];
            j++;
        }
    }

    // If all elements are non-negative or all are negative, return
    if (j == n || j == 0) {
        return;
    }

    // Second pass: copy all negative elements
    for (int i = 0; i < n; i++) {
        if (arr[i] < 0) {
            temp[j] = arr[i];
            j++;
        }
    }

    // Copy back to original array
    for (int k = 0; k < n; k++) {
        arr[k] = temp[k];
    }
}
