    public static int minimumBox(int[] arr, int n) {
        Deque<Integer> q = new ArrayDeque<>();

        // Create a copy of the first n elements and sort them
        int[] sortedArr = Arrays.copyOf(arr, n);
        Arrays.sort(sortedArr);

        q.addLast(sortedArr[0]);

        for (int i = 1; i < n; i++) {
            int now = q.peekFirst();
            if (sortedArr[i] >= 2 * now) {
                q.pollFirst();
            }
            q.addLast(sortedArr[i]);
        }

        return q.size();
