import java.util.HashMap;
import java.util.Map;

class Solution {
    public static int findSum(int[] A, int[] B, int n) {
        // Create a HashMap to store the count of each element
        Map<Integer, Integer> hash = new HashMap<>();

        // Count occurrences of elements from both arrays
        for (int i = 0; i < n; i++) {
            hash.put(A[i], hash.getOrDefault(A[i], 0) + 1);
            hash.put(B[i], hash.getOrDefault(B[i], 0) + 1);
        }

        // Sum elements that occur exactly once
        int sum = 0;
        for (Map.Entry<Integer, Integer> entry : hash.entrySet()) {
            if (entry.getValue() == 1) {
                sum += entry.getKey();
            }
        }

        return sum;
    }
}
