import java.util.*;

public class Solution {
    public static void antiSpiralTraversal(int m, int n, int[][] a) {
        int k = 0;
        int l = 0;
        Stack<Integer> stk = new Stack<>();

        while (k <= m && l <= n) {
            // Traverse right
            for (int i = l; i <= n; i++) {
                stk.push(a[k][i]);
            }
            k++;

            // Traverse down
            for (int i = k; i <= m; i++) {
                stk.push(a[i][n]);
            }
            n--;

            // Traverse left
            if (k <= m) {
                for (int i = n; i >= l; i--) {
                    stk.push(a[m][i]);
                }
                m--;
            }

            // Traverse up
            if (l <= n) {
                for (int i = m; i >= k; i--) {
                    stk.push(a[i][l]);
                }
                l++;
            }
        }

        // Print elements in reverse order
        while (!stk.isEmpty()) {
            System.out.print(stk.pop() + " ");
        }
    }
}
