public class BestFit {
    public static void bestFit(int[] blockSize, int m, int[] processSize, int n) {
        // Array to store allocation for each process
        int[] allocation = new int[n];

        // Initialize allocation array with -1 (not allocated)
        Arrays.fill(allocation, -1);

        // Process each process
        for (int i = 0; i < n; i++) {
            int bestIdx = -1;

            // Find the best block for current process
            for (int j = 0; j < m; j++) {
                if (blockSize[j] >= processSize[i]) {
                    if (bestIdx == -1) {
                        bestIdx = j;
                    } else if (blockSize[bestIdx] > blockSize[j]) {
                        bestIdx = j;
                    }
                }
            }

            // If we found a block for current process
            if (bestIdx != -1) {
                allocation[i] = bestIdx;
                blockSize[bestIdx] -= processSize[i];
            }
        }

        // Print results
        System.out.println("Process No.Process Size     Block no.");
        for (int i = 0; i < n; i++) {
            System.out.print((i + 1) + "         " + processSize[i] + "         ");
            if (allocation[i] != -1) {
                System.out.println(allocation[i] + 1);
            } else {
                System.out.println("Not Allocated");
