    // Binary search function that also checks adjacent elements
    public static int binarySearch(int[] arr, int l, int r, int x) {
        if (r >= l) {
            int mid = l + (r - l) / 2;

            // Check if the middle element is the target
            if (arr[mid] == x)
                return mid;

            // Check if the element before mid is the target
            if (mid > l && arr[mid - 1] == x)
                return (mid - 1);

            // Check if the element after mid is the target
            if (mid < r && arr[mid + 1] == x)
                return (mid + 1);

            // If the target is smaller than mid, search in the left subarray
            // but skip the element we already checked (mid-1)
            if (arr[mid] > x)
                return binarySearch(arr, l, mid - 2, x);

            // If the target is larger than mid, search in the right subarray
            // but skip the element we already checked (mid+1)
            return binarySearch(arr, mid + 2, r, x);
        }

