class Solution {
    public static void sortArray(int arr[], int n, int A, int B, int C) {
        // Transform array elements using quadratic equation
        for (int i = 0; i < n; i++) {
            arr[i] = (A * arr[i] * arr[i] + B * arr[i] + C);
        }

        // Find index and value of maximum element
        int index = Integer.MIN_VALUE;
        int maximum = Integer.MIN_VALUE;
        for (int i = 0; i < n; i++) {
            if (maximum < arr[i]) {
                index = i;
                maximum = arr[i];
            }
        }

        int i = 0;
        int j = n - 1;
        int[] new_arr = new int[n];
        int k = 0;

        // Sort elements before and after maximum
        while (i < index && j > index) {
            if (arr[i] < arr[j]) {
                new_arr[k] = arr[i];
                k++;
                i++;
            } else {
                new_arr[k] = arr[j];
                k++;
                j--;
            }
        }

        // Add remaining elements from left side
        while (i < index) {
            new_arr[k] = arr[i];
            k++;
            i++;
        }

        // Add remaining elements from right side
        while (j > index) {
            new_arr[k] = arr[j];
            k++;
            j--;
        }

        new_arr[n - 1] = maximum;

        // Copy back sorted array
        for (int idx = 0; idx < n; idx++) {
            arr[idx] = new_arr[idx];
        }
    }
}
