public class TilingCounter {
    public static int countWays(int n) {
        int[] A = new int[n + 1];
        int[] B = new int[n + 1];

        A[0] = 1;
        A[1] = 0;
        B[0] = 0;
        B[1] = 1;

        for (int i = 2; i <= n; i++) {
            A[i] = A[i - 2] + 2 * B[i - 1];
            B[i] = A[i - 1] + B[i - 2];
        }

        return A[n];
    }

    // Example usage
    public static void main(String[] args) {
        int n = 4;
        System.out.println("Number of ways for n = " + n + ": " + countWays(n));
    }
}
